// ANTES — callback hell:
func carregarPerfil(id: UUID, completion: @escaping (Result<Perfil, Error>) -> Void) {
    buscarUsuario(id: id) { resultado in
        switch resultado {
        case .success(let usuario):
            buscarFoto(url: usuario.fotoURL) { fotoResultado in
                switch fotoResultado {
                case .success(let foto):
                    completion(.success(Perfil(usuario: usuario, foto: foto)))
                case .failure(let erro):
                    completion(.failure(erro))
                }
            }
        case .failure(let erro):
            completion(.failure(erro))
        }
    }
}

// DEPOIS — async/await, legível como código síncrono:
func carregarPerfil(id: UUID) async throws -> Perfil {
    let usuario = try await buscarUsuario(id: id)
    let foto = try await buscarFoto(url: usuario.fotoURL)
    return Perfil(usuario: usuario, foto: foto)
}

// Função assíncrona que pode falhar:
func buscarTarefas() async throws -> [Tarefa] {
    let url = URL(string: "https://api.app.com/tarefas")!
    let (data, response) = try await URLSession.shared.data(from: url)

    guard let httpResponse = response as? HTTPURLResponse,
          httpResponse.statusCode == 200 else {
        throw APIError.respostaInvalida
    }

    return try JSONDecoder().decode([Tarefa].self, from: data)
}

// Chamada com tratamento de erro:
func carregarDados() async {
    do {
        let tarefas = try await buscarTarefas()
        self.tarefas = tarefas  // atualiza o estado
    } catch APIError.respostaInvalida {
        self.erro = "Servidor retornou resposta inválida"
    } catch {
        self.erro = error.localizedDescription
    }
}

// Executando async de um contexto síncrono:
Button("Carregar") {
    // Button action é síncrona — precisa de Task:
    Task {
        await carregarDados()
    }
}

