// @MainActor na classe — todas as propriedades e métodos são na main thread:
@MainActor
@Observable
class TarefasViewModel {
    var tarefas: [Tarefa] = []
    var carregando = false

    // Mesmo sendo async, executa na main thread:
    func carregar() async throws {
        carregando = true
        // await libera a main thread durante a espera:
        tarefas = try await TarefaService.buscar()
        // Retoma na main thread automaticamente:
        carregando = false  // atualização de UI — seguro!
    }
}

