// actor — estado thread-safe sem locks manuais:
actor Cache {
    private var dados: [String: Data] = [:]

    func salvar(chave: String, data: Data) {
        dados[chave] = data  // thread-safe — actor garante serialização
    }

    func buscar(chave: String) -> Data? {
        dados[chave]
    }

    func limpar() {
        dados.removeAll()
    }
}

